/**
 * Returns income/expense/category breakdown and trends over the requested period
 * @summary Get a financial report summary
 */
export const GetReportSummaryQueryParams = zod.object({
    "period": zod.enum(['monthly', 'yearly'])
});
export const GetReportSummaryResponse = zod.object({
    "totalIncome": zod.number(),
    "totalExpense": zod.number(),
    "netSavings": zod.number(),
    "categoryBreakdown": zod.array(zod.object({
        "category": zod.string(),
        "amount": zod.number(),
        "color": zod.string()
    })),
    "trend": zod.array(zod.object({
        "period": zod.string(),
        "income": zod.number(),
        "expense": zod.number()
    })),
    "netWorthTrend": zod.array(zod.object({
        "period": zod.string(),
        "netWorth": zod.number()
    }))
});
